#include "iman.h"
void gcw(const char*i,char*c,size_t sz){const char*s=strchr(i,' ');if(s){s++;const char*sp=strchr(s,' ');if(sp){size_t l=sp-s;if(l>=sz)l=sz-1;strncpy(c,s,l);c[l]='\0';}else{strncpy(c,s,sz-1);c[sz-1]='\0';}}else c[0]='\0';}
void sht(char*i,char*o){int in=0;size_t j=0;for(size_t k=0;i[k];k++){if(i[k]=='<')in=1;else if(i[k]=='>')in=0;else if(!in)o[j++]=i[k];}o[j]='\0';}
void ue(const char*s,char*d,size_t sz){const char*h="0123456789ABCDEF";size_t p=0;for(size_t i=0;s[i]&&p<sz-1;i++){if(isalnum((unsigned char)s[i])||s[i]=='-'||s[i]=='_'||s[i]=='.'||s[i]=='~')d[p++]=s[i];else if(p+3<sz){d[p++]='%';d[p++]=h[(unsigned char)s[i]>>4];d[p++]=h[(unsigned char)s[i]&15];}}d[p]='\0';}
void sr(int s,const char*c){char req[BUFFER_SIZE],enc[BUFFER_SIZE];ue(c,enc,sizeof(enc));snprintf(req,sizeof(req)+100,"GET /?topic=%s&section=all HTTP/1.1\r\nHost: " HOST "\r\nConnection: close\r\n\r\n",enc);send(s,req,strlen(req),0);}
void rapr(int s,const char*c){char buf[BUFFER_SIZE],cl[BUFFER_SIZE*10],ans[BUFFER_SIZE*20]="";ssize_t br;int in=0;while((br=recv(s,buf,BUFFER_SIZE-1,0))>0){buf[br]='\0';if(!in){char*bs=strstr(buf,"<html>");if(bs){in=1;sht(bs,cl);strncat(ans,cl,sizeof(ans)-strlen(ans)-1);}}else{sht(buf,cl);strncat(ans,cl,sizeof(ans)-strlen(ans)-1);}}printf("%s",ans);}
void pic(const char*i){char cmd[256];gcw(i,cmd,sizeof(cmd));if(strlen(cmd)==0){printf("Usage: iMan <cmd>\n");return;}int s=socket(AF_INET,SOCK_STREAM,0);if(s<0){perror("socket");return;}struct addrinfo hints,*res;memset(&hints,0,sizeof(hints));hints.ai_family=AF_INET;hints.ai_socktype=SOCK_STREAM;int st=getaddrinfo(HOST,PORT,&hints,&res);if(st!=0){fprintf(stderr,"getaddrinfo: %s\n",gai_strerror(st));close(s);return;}if(connect(s,res->ai_addr,res->ai_addrlen)<0){perror("connect");close(s);return;}freeaddrinfo(res);sr(s,cmd);rapr(s,cmd);close(s);}
